INSERT INTO public.exercises (name, movement_pattern, primary_muscle, secondary_muscles, equipment, difficulty, description, tips) VALUES
  ('Barbell Bench Press', 'push', 'chest', '{triceps,shoulders}', 'barbell', 3, 'Lie on a flat bench and press a barbell from chest level to full arm extension.', 'Keep your shoulder blades retracted and feet flat on the floor. Control the descent.'),
  ('Incline Barbell Bench Press', 'push', 'chest', '{shoulders,triceps}', 'barbell', 3, 'Press a barbell overhead while lying on a bench set to 30-45 degrees.', 'Angle the bench at 30-45°. Avoid flaring elbows excessively to protect the shoulder joint.'),
  ('Dumbbell Bench Press', 'push', 'chest', '{triceps,shoulders}', 'dumbbell', 2, 'Press two dumbbells from chest height to lockout while lying on a flat bench.', 'Allow a slight arch in the lower back. Lower the dumbbells until your elbows are at 90°.'),
  ('Incline Dumbbell Press', 'push', 'chest', '{shoulders,triceps}', 'dumbbell', 3, 'Press dumbbells overhead on an incline bench to emphasize the upper chest.', 'Keep wrists neutral and drive the dumbbells up in a slight arc. Don''t bounce at the bottom.'),
  ('Machine Chest Press', 'push', 'chest', '{triceps,shoulders}', 'machine', 1, 'Push handles forward on a seated chest press machine until arms are extended.', 'Adjust the seat so handles align with mid-chest. Focus on a full range of motion.'),
  ('Cable Fly', 'push', 'chest', '{shoulders}', 'cable', 2, 'Bring cable handles together in a wide arc in front of the chest, squeezing the pecs.', 'Keep a slight bend in the elbows throughout. Control the negative for a deep stretch.'),
  ('Push-up', 'push', 'chest', '{triceps,shoulders,core}', 'bodyweight', 1, 'Lower your body to the floor and press back up while maintaining a straight line from head to heels.', 'Engage your core and avoid sagging hips. Scale by elevating hands to reduce difficulty.'),
  ('Band-Resisted Push-up', 'push', 'chest', '{triceps,shoulders}', 'band', 2, 'Perform a push-up with a resistance band looped across the back and under the hands for added load.', 'Choose a band tension that lets you complete 8-12 reps with good form.'),
  ('Overhead Press', 'push', 'shoulders', '{triceps,core}', 'barbell', 3, 'Press a barbell from shoulder height to overhead while standing.', 'Brace your core hard. Tuck chin back as the bar passes your face, then push your head through.'),
  ('Dumbbell Shoulder Press', 'push', 'shoulders', '{triceps}', 'dumbbell', 2, 'Press two dumbbells from shoulder level to full lockout overhead while seated or standing.', 'Don''t arch your back excessively. Lower until elbows are at roughly 90°.'),
  ('Arnold Press', 'push', 'shoulders', '{triceps}', 'dumbbell', 3, 'Start with palms facing you at shoulder height, rotate outward as you press overhead.', 'Use a smooth rotation. This targets all three deltoid heads more evenly than a standard press.'),
  ('Machine Shoulder Press', 'push', 'shoulders', '{triceps}', 'machine', 1, 'Push handles overhead on a seated shoulder press machine.', 'Adjust the seat so the handles start at ear level. Avoid locking out aggressively.'),
  ('Lateral Raise', 'push', 'shoulders', '{traps}', 'dumbbell', 2, 'Raise dumbbells out to the sides until arms are parallel with the floor.', 'Lead with the elbows, not the hands. Use a slight forward lean to reduce impingement risk.'),
  ('Cable Lateral Raise', 'push', 'shoulders', '{traps}', 'cable', 2, 'Raise a low-cable handle out to the side to shoulder height.', 'Stand sideways to the cable for constant tension throughout the range of motion.'),
  ('Dips', 'push', 'triceps', '{chest,shoulders}', 'bodyweight', 3, 'Lower yourself between parallel bars by bending the elbows, then press back up.', 'Lean forward slightly to involve more chest; stay upright to isolate triceps. Go to at least 90° elbow bend.'),
  ('Tricep Pushdown', 'push', 'triceps', '{}', 'cable', 1, 'Push a cable attachment down from chest height until the arms are fully extended.', 'Keep elbows pinned at your sides. Squeeze the triceps at the bottom.'),
  ('Close-Grip Bench Press', 'push', 'triceps', '{chest,shoulders}', 'barbell', 3, 'Bench press with a narrower-than-shoulder-width grip to shift emphasis to the triceps.', 'Hands about shoulder-width apart. Keep elbows tucked close to the body.'),
  ('Overhead Tricep Extension', 'push', 'triceps', '{}', 'dumbbell', 2, 'Hold a dumbbell overhead with both hands and lower it behind the head, then extend.', 'Keep upper arms vertical and close to the ears. Focus on the stretch at the bottom.'),
  ('Barbell Row', 'pull', 'back', '{biceps,core}', 'barbell', 3, 'Hinge forward and pull a barbell into the lower chest or upper abdomen.', 'Keep your back flat and core braced. Pull to the belly button for lower lats, to the sternum for upper back.'),
  ('Dumbbell Row', 'pull', 'back', '{biceps}', 'dumbbell', 2, 'Row a dumbbell to the hip while supporting yourself on a bench with the opposite hand and knee.', 'Drive the elbow past the torso. Avoid rotating the trunk excessively.'),
  ('Pull-up', 'pull', 'back', '{biceps,forearms}', 'bodyweight', 4, 'Hang from a bar with an overhand grip and pull your chin above the bar.', 'Initiate by depressing the shoulder blades. Avoid kipping until you can do strict reps.'),
  ('Lat Pulldown', 'pull', 'back', '{biceps}', 'cable', 2, 'Pull a wide bar attachment down to the upper chest while seated.', 'Lean back slightly and pull the bar to the collarbone. Squeeze shoulder blades together at the bottom.'),
  ('Seated Cable Row', 'pull', 'back', '{biceps,traps}', 'cable', 2, 'Pull a cable handle to the abdomen while seated with feet braced.', 'Keep your torso upright—don''t lean back excessively. Think about pulling with your elbows.'),
  ('T-Bar Row', 'pull', 'back', '{biceps,core}', 'barbell', 3, 'Straddle a landmine barbell and row the loaded end toward the chest.', 'Use a V-grip handle for a neutral grip. Maintain a flat back throughout.'),
  ('Pendlay Row', 'pull', 'back', '{core,biceps}', 'barbell', 4, 'Row a barbell explosively from a dead stop on the floor to the torso each rep.', 'Reset fully on the floor between reps. Use a strict back position—no momentum from the legs.'),
  ('Machine Row', 'pull', 'back', '{biceps}', 'machine', 1, 'Pull handles toward your torso on a seated row machine.', 'Focus on squeezing the shoulder blades together at peak contraction.'),
  ('Band Row', 'pull', 'back', '{biceps}', 'band', 1, 'Anchor a band at waist height and row the handles to the abdomen.', 'Great for warm-ups and high-rep finishers. Hold the peak contraction for 1-2 seconds.'),
  ('Chin-up', 'pull', 'biceps', '{back,forearms}', 'bodyweight', 3, 'Hang from a bar with an underhand grip and pull your chin above the bar.', 'Supinated grip biases the biceps more than pull-ups. Full dead hang at the bottom.'),
  ('Barbell Curl', 'pull', 'biceps', '{forearms}', 'barbell', 2, 'Curl a barbell from hip level to shoulder height with a supinated grip.', 'Keep elbows stationary at your sides. Avoid swinging the torso.'),
  ('Dumbbell Curl', 'pull', 'biceps', '{forearms}', 'dumbbell', 1, 'Curl dumbbells alternately or simultaneously from arms-length to shoulder height.', 'Supinate at the top for extra bicep contraction. Control the eccentric.'),
  ('Hammer Curl', 'pull', 'biceps', '{forearms}', 'dumbbell', 2, 'Curl dumbbells with a neutral (palms facing each other) grip.', 'Targets the brachialis and brachioradialis in addition to the biceps. Keep wrists locked.'),
  ('Cable Curl', 'pull', 'biceps', '{forearms}', 'cable', 1, 'Curl a low-cable bar or handle to shoulder height.', 'Constant tension from the cable makes this excellent for time-under-tension training.'),
  ('Preacher Curl', 'pull', 'biceps', '{forearms}', 'machine', 2, 'Curl on a preacher bench that braces the upper arms, isolating the biceps.', 'Don''t fully extend at the bottom to keep tension on the muscle and protect the elbow.'),
  ('Face Pull', 'pull', 'shoulders', '{traps,back}', 'cable', 1, 'Pull a rope attachment toward the face with elbows high, targeting rear deltoids.', 'Externally rotate at the end of each rep. Use light weight and high reps.'),
  ('Reverse Fly', 'pull', 'shoulders', '{traps,back}', 'dumbbell', 2, 'Bend forward and raise dumbbells out to the sides to target the rear deltoids.', 'Keep a slight bend in the elbows. Focus on squeezing the shoulder blades together.'),
  ('Band Pull-Apart', 'pull', 'shoulders', '{traps,back}', 'band', 1, 'Hold a band at arm''s length and pull it apart by squeezing the rear delts.', 'Excellent warm-up and posture exercise. Aim for 15-25 reps per set.'),
  ('Barbell Shrug', 'pull', 'traps', '{forearms}', 'barbell', 2, 'Hold a barbell at arm''s length and shrug your shoulders toward your ears.', 'Hold the top position for a full second. Avoid rolling the shoulders.'),
  ('Dumbbell Shrug', 'pull', 'traps', '{forearms}', 'dumbbell', 1, 'Hold dumbbells at your sides and shrug your shoulders up.', 'Dumbbells allow a more natural hand position. Use straps if grip is limiting.'),
  ('Wrist Curl', 'pull', 'forearms', '{}', 'dumbbell', 1, 'Rest forearms on a bench with wrists hanging off the edge; curl the wrist up.', 'Use light weight and high reps (15-20). Let the dumbbell roll to the fingertips for extra ROM.'),
  ('Reverse Barbell Curl', 'pull', 'forearms', '{biceps}', 'barbell', 2, 'Curl a barbell with an overhand (pronated) grip to target the brachioradialis and forearm extensors.', 'Use lighter weight than standard curls. Keep elbows pinned to your sides.'),
  ('Back Squat', 'squat', 'quads', '{glutes,hamstrings,core}', 'barbell', 4, 'Place a barbell on the upper back and squat down until hips are below knee level.', 'Drive knees out over toes. Keep chest up and core braced. Aim for at least parallel depth.'),
  ('Front Squat', 'squat', 'quads', '{glutes,core}', 'barbell', 4, 'Hold a barbell in a front rack position and squat to depth.', 'Keep elbows high to prevent the bar from rolling forward. Requires good wrist and thoracic mobility.'),
  ('Goblet Squat', 'squat', 'quads', '{glutes,core}', 'dumbbell', 2, 'Hold a dumbbell at chest height and squat between your legs.', 'Great for learning squat mechanics. Push knees out and keep the torso upright.'),
  ('Leg Press', 'squat', 'quads', '{glutes}', 'machine', 2, 'Push a weighted sled away using your legs on a 45° leg press machine.', 'Don''t lock out knees at the top. Place feet higher on the platform to emphasize glutes.'),
  ('Bulgarian Split Squat', 'squat', 'quads', '{glutes,hamstrings}', 'dumbbell', 3, 'Lunge with the rear foot elevated on a bench behind you.', 'Keep most of your weight on the front foot. Lean the torso slightly forward for glute emphasis.'),
  ('Hack Squat', 'squat', 'quads', '{glutes}', 'machine', 2, 'Squat on a hack squat machine with the back supported on an angled pad.', 'Place feet lower on the platform for more quad emphasis. Control the eccentric.'),
  ('Leg Extension', 'squat', 'quads', '{}', 'machine', 1, 'Extend the knees against a padded lever on a leg extension machine.', 'Use a controlled tempo—avoid swinging the weight. Pause at full extension.'),
  ('Walking Lunge', 'squat', 'quads', '{glutes,hamstrings}', 'dumbbell', 3, 'Step forward into a lunge, then bring the rear foot forward to continue walking.', 'Take long steps for glute emphasis, shorter steps for quad emphasis. Keep torso upright.'),
  ('Pistol Squat', 'squat', 'quads', '{glutes,core}', 'bodyweight', 5, 'Single-leg squat performed all the way to the bottom with the free leg extended forward.', 'Progress by using a box or TRX for assistance. Requires excellent mobility and balance.'),
  ('Band Squat', 'squat', 'quads', '{glutes}', 'band', 1, 'Stand on a resistance band and squat while holding the band at shoulder height for added resistance.', 'Useful for warm-ups and high-rep sets. Band tension increases at the top of the movement.'),
  ('Zercher Squat', 'squat', 'quads', '{core,glutes}', 'barbell', 4, 'Hold a barbell in the crook of your elbows and squat to depth.', 'Wrap the bar in a pad for comfort. Forces an extremely upright torso position.'),
  ('Standing Calf Raise', 'squat', 'calves', '{}', 'machine', 1, 'Rise onto the toes under a shoulder-padded calf raise machine.', 'Pause at the top and get a full stretch at the bottom. Slow eccentric (3-4 seconds).'),
  ('Seated Calf Raise', 'squat', 'calves', '{}', 'machine', 1, 'Raise the heels while seated with a pad across the knees, targeting the soleus.', 'The bent-knee position shifts emphasis to the soleus. Use a 2-second pause at the top.'),
  ('Dumbbell Calf Raise', 'squat', 'calves', '{}', 'dumbbell', 1, 'Hold a dumbbell and stand on a step or plate; rise onto the toes and lower for a full stretch.', 'Perform one leg at a time for balanced development. Use a ledge for full range of motion.'),
  ('Deadlift', 'hinge', 'hamstrings', '{back,glutes,core,forearms}', 'barbell', 5, 'Lift a barbell from the floor to hip level by extending the hips and knees.', 'Keep the bar close to the body. Brace your core, push the floor away, and lock out with the glutes.'),
  ('Romanian Deadlift', 'hinge', 'hamstrings', '{glutes,back}', 'barbell', 3, 'Lower a barbell along the thighs by hinging at the hips with a slight knee bend.', 'Push your hips back like closing a door with your glutes. Feel the stretch in the hamstrings.'),
  ('Dumbbell Romanian Deadlift', 'hinge', 'hamstrings', '{glutes}', 'dumbbell', 2, 'Hinge at the hips and lower dumbbells along the legs with a slight knee bend.', 'Dumbbells allow a more natural path and better range of motion than a barbell for some lifters.'),
  ('Good Morning', 'hinge', 'hamstrings', '{back,glutes}', 'barbell', 3, 'With a barbell on the upper back, bow forward by hinging at the hips, then return to standing.', 'Use moderate weight and a controlled tempo. Keep the knees slightly bent.'),
  ('Leg Curl', 'hinge', 'hamstrings', '{}', 'machine', 1, 'Curl the heels toward the glutes against a padded lever on a lying or seated leg curl machine.', 'Control the eccentric—don''t let the weight slam down. Squeeze the hamstrings at peak contraction.'),
  ('Nordic Hamstring Curl', 'hinge', 'hamstrings', '{}', 'bodyweight', 4, 'Kneel with ankles anchored and slowly lower your torso forward, resisting with the hamstrings.', 'One of the best exercises for hamstring injury prevention. Use a push-off from the floor to assist.'),
  ('Band Good Morning', 'hinge', 'hamstrings', '{glutes}', 'band', 2, 'Loop a band behind the neck and under the feet; hinge forward and return to standing.', 'Useful for warm-ups and light accessory work. Increasing tension at the top reinforces lockout.'),
  ('Hip Thrust', 'hinge', 'glutes', '{hamstrings}', 'barbell', 3, 'Sit on the floor with upper back against a bench, roll a barbell over the hips, and thrust upward.', 'Drive through the heels and squeeze glutes at the top. Use a bar pad for comfort.'),
  ('Glute Bridge', 'hinge', 'glutes', '{hamstrings}', 'bodyweight', 1, 'Lie on the floor and drive the hips up by squeezing the glutes.', 'Great for activation before heavy lifts. Hold the top for 2-3 seconds each rep.'),
  ('Cable Pull-Through', 'hinge', 'glutes', '{hamstrings}', 'cable', 2, 'Face away from a low cable, hinge forward, then drive the hips forward to pull the rope through the legs.', 'Hinge deep and snap the hips through at the top. Constant cable tension is the key benefit.'),
  ('Kettlebell Swing', 'hinge', 'glutes', '{hamstrings,core}', 'dumbbell', 2, 'Hike a weight between the legs and drive the hips forward to swing it to chest height.', 'Power comes from the hip snap, not the arms. Keep arms relaxed and core braced. Can use a dumbbell or kettlebell.'),
  ('Sumo Deadlift', 'hinge', 'glutes', '{hamstrings,back,core}', 'barbell', 4, 'Deadlift with a wide stance and hands inside the knees, shifting more emphasis to the glutes.', 'Push the knees out over the toes. The wider stance shortens the range of motion compared to conventional.'),
  ('Plank', 'core', 'core', '{shoulders}', 'bodyweight', 1, 'Hold a push-up position (or forearm position) with the body in a straight line.', 'Squeeze glutes and brace as if someone will poke your stomach. Build up to 60-second holds.'),
  ('Cable Woodchop', 'core', 'core', '{shoulders}', 'cable', 2, 'Rotate the torso to pull a cable diagonally from high to low (or low to high).', 'The power comes from the hips and core rotation, not the arms. Control the return.'),
  ('Hanging Leg Raise', 'core', 'core', '{forearms}', 'bodyweight', 3, 'Hang from a pull-up bar and raise the legs to at least 90° by curling the pelvis.', 'Avoid swinging. Bend knees to make it easier; keep legs straight for a greater challenge.'),
  ('Ab Rollout', 'core', 'core', '{}', 'bodyweight', 3, 'Kneel and roll an ab wheel (or barbell) forward, extending the body, then pull back.', 'Only go as far as you can control without your lower back collapsing. Progress range over time.'),
  ('Russian Twist', 'core', 'core', '{}', 'dumbbell', 2, 'Sit with knees bent, lean back slightly, and rotate a dumbbell from side to side.', 'Lift your feet off the ground for added difficulty. Focus on controlled rotation, not speed.'),
  ('Pallof Press', 'core', 'core', '{}', 'cable', 2, 'Stand sideways to a cable, press the handle straight out from the chest, and resist the rotation.', 'Anti-rotation is the goal. Hold the extended position for 2-3 seconds per rep.'),
  ('Machine Crunch', 'core', 'core', '{}', 'machine', 1, 'Crunch forward against resistance on a seated ab machine.', 'Focus on curling the rib cage toward the pelvis, not just bending at the hips.'),
  ('Dead Bug', 'core', 'core', '{}', 'bodyweight', 1, 'Lie on the back and alternately extend opposite arm and leg while keeping the lower back pressed to the floor.', 'Exhale fully as you extend. If your lower back lifts off, reduce the range of motion.'),
  ('Band Anti-Rotation Press', 'core', 'core', '{}', 'band', 2, 'Similar to a Pallof press but using a resistance band anchored to the side.', 'Great for home workouts. Step further from the anchor to increase resistance.'),
  ('Farmer''s Walk', 'carry', 'forearms', '{traps,core}', 'dumbbell', 2, 'Hold heavy dumbbells at your sides and walk for distance or time.', 'Stand tall, keep shoulders packed, and take short, quick steps. Grip will often be the limiting factor.'),
  ('Suitcase Carry', 'carry', 'core', '{forearms,traps}', 'dumbbell', 2, 'Carry a heavy dumbbell on one side while walking, challenging the core to resist lateral flexion.', 'Keep the torso perfectly upright—don''t lean to the loaded side. Walk 30-40 meters per set.'),
  ('Trap Bar Carry', 'carry', 'traps', '{forearms,core}', 'barbell', 3, 'Pick up a loaded trap bar and walk for distance, building total-body stability and grip.', 'Allows heavier loads than dumbbell carries. Keep a tall posture and brace the core throughout.'),
  ('Overhead Carry', 'carry', 'shoulders', '{core,traps}', 'dumbbell', 3, 'Press a dumbbell overhead and walk for distance while keeping the arm locked out.', 'Challenges shoulder stability and core anti-lateral flexion. Start light and progress slowly.');
